defineConfig({
  getRateLimitIdentifier: (ctx) => ctx.state.user?.id,
  defaultRateLimit: { max: 100, windowMs: 60_000 },
});

defineConfig({
  defaultRateLimit: {
    max: 100,       // 100 requests
    windowMs: 60_000, // per minute
  },
});

// Stricter limit for a sensitive endpoint
export default defineApi({
  rateLimit: { max: 10, windowMs: 60_000 },
  // ...
});

// Disable rate limiting for this route
export default defineApi({
  rateLimit: false,
  // ...
});

// Login endpoint: 5 attempts per minute, locked out for 1 hour
export default defineApi({
  rateLimit: {
    max: 5,
    windowMs: 60_000,
    blockDurationMs: 3_600_000, // 1 hour lockout
  },
  // ...
});

// OTP endpoint: 3 attempts per 5 min, locked out for 24 hours
export default defineApi({
  rateLimit: {
    max: 3,
    windowMs: 300_000,
    blockDurationMs: 86_400_000,
  },
  // ...
});

import { redisCache, memoryCache } from "@hushkey/howl/api/cache";

const redis = new Redis(Deno.env.get("REDIS_URL"));

defineConfig({
  // Response cache — per-instance is fine (responses are idempotent)
  cache: memoryCache({ maxSize: 1000 }),
  // Rate limit counters — must be shared across all instances
  rateLimitCache: redisCache(redis),
});

// Custom adapter — implement `incr` for safe shared-backend use.
function myAdapter(): CacheAdapter {
  return {
    async get(key) { /* … */ },
    async set(key, value, ttl) { /* … */ },
    async delete(key) { /* … */ },
    async incr(key, ttl) {
      // Atomic counter+TTL primitive on whichever backend you're using.
      // Must apply ttl on first write; subsequent calls just bump the count.
      return await myBackend.atomicIncr(key, ttl);
    },
  };
}
